import { evaluate } from '@mdx-js/mdx';
import { render, screen } from '@testing-library/react';
import { Fragment, jsx, jsxs } from 'react/jsx-runtime';

import { Wrapper } from '@/tests/components/lib/common';
import { useMDXComponents } from './mdx-components';

async function renderMDX(source: string) {
    const { default: MDXContent } = await evaluate(source, {
        Fragment,
        jsx,
        jsxs,
        useMDXComponents,
    });
    render(
        <Wrapper>
            <MDXContent />
        </Wrapper>,
    );
}

describe('useMDXComponents', () => {
    describe('external links (a)', () => {
        it('adds noopener and noreferrer when target is _blank', async () => {
            await renderMDX('<a href="https://example.com" target="_blank">Visit</a>');

            const link = screen.getByRole('link', { name: 'Visit' });
            expect(link).toHaveAttribute('rel', expect.stringContaining('noopener'));
            expect(link).toHaveAttribute('rel', expect.stringContaining('noreferrer'));
        });

        it('does not add security tokens when target is not _blank', async () => {
            await renderMDX('[Visit](https://example.com)');

            const link = screen.getByRole('link', { name: 'Visit' });
            expect(link).not.toHaveAttribute('rel', expect.stringContaining('noopener'));
        });

        it('does not duplicate noopener/noreferrer when already present in rel', async () => {
            await renderMDX(
                '<a href="https://example.com" target="_blank" rel="noopener noreferrer">Visit</a>',
            );

            const link = screen.getByRole('link', { name: 'Visit' });
            const tokens = (link.getAttribute('rel') ?? '').split(/\s+/);
            expect(tokens.filter(t => t === 'noopener')).toHaveLength(1);
            expect(tokens.filter(t => t === 'noreferrer')).toHaveLength(1);
        });

        it('preserves href and other attributes', async () => {
            await renderMDX('<a href="https://example.com" id="my-link" target="_blank">Visit</a>');

            const link = screen.getByRole('link', { name: 'Visit' });
            expect(link).toHaveAttribute('href', 'https://example.com');
            expect(link).toHaveAttribute('id', 'my-link');
        });
    });

    describe('fenced code blocks (pre/code)', () => {
        it('preserves the language class from the inner code element', async () => {
            await renderMDX('```js\nconst x = 1;\n```');

            expect(document.querySelector('.language-js')).not.toBeNull();
        });

        it('preserves code content', async () => {
            await renderMDX('```js\nconst x = 1;\n```');

            expect(screen.getByText(/const x = 1/)).toBeInTheDocument();
        });

        it('renders inline code without a language class', async () => {
            await renderMDX('Use `console.log` for debugging.');

            expect(screen.getByText('console.log')).toBeInTheDocument();
            expect(document.querySelector('.language-js')).toBeNull();
        });
    });
});

